## 二、新模块骨架代码

### 2.1 新建 `src/reactive/Reactive.ixx`

创建文件 `src/reactive/Reactive.ixx`，内容如下：

```cpp
module;

#include <cassert>
#include <cstddef>
#include <functional>
#include <memory>
#include <type_traits>
#include <utility>
#include <vector>

export module Nandina.Reactive;

export namespace Nandina {

// ─── 前向声明 ────────────────────────────────────────────────────────────────

class EffectScope;

namespace detail {
    // 当前正在执行的 Effect 的通知回调（线程局部，用于自动依赖追踪）
    // 当 Effect 执行时，其读取的每个 Signal 都将此回调注册为观察者
    inline thread_local std::function<void()>* current_invalidator = nullptr;

    struct ObserverEntry {
        std::size_t           id     = 0;
        bool                  active = true;
        std::function<void()> invalidate;  // 被依赖的 Signal 变化时调用
    };
}

// ─── Signal<T> ───────────────────────────────────────────────────────────────
// 响应式可读写状态容器。
// 读取时（operator()）自动将当前 Effect 注册为观察者。
// 写入时（set）通知所有活跃观察者。

template<typename T>
class ReadSignal;  // 前向声明

template<typename T>
class Signal {
public:
    explicit Signal(T initial_value) : value_(std::move(initial_value)) {}

    // 禁止拷贝，允许移动
    Signal(const Signal&) = delete;
    auto operator=(const Signal&) -> Signal& = delete;
    Signal(Signal&&) noexcept = default;
    auto operator=(Signal&&) noexcept -> Signal& = default;

    // 读取当前值，同时注册依赖
    [[nodiscard]] auto operator()() const -> const T& {
        track_access();
        return value_;
    }

    [[nodiscard]] auto get() const -> const T& {
        return (*this)();
    }

    // 写入新值，值变化时通知所有观察者
    auto set(T new_value) -> void {
        if (value_ == new_value) return;
        value_ = std::move(new_value);
        notify();
    }

    // 返回只读视图（传给子组件的 Props，防止子组件反向写入）
    [[nodiscard]] auto as_read_only() const -> ReadSignal<T>;

private:
    friend class ReadSignal<T>;

    auto track_access() const -> void {
        if (detail::current_invalidator) {
            // 为当前 Effect 注册一个观察者条目
            const std::size_t id = next_id_++;
            observers_.push_back(detail::ObserverEntry{
                .id         = id,
                .active     = true,
                .invalidate = *detail::current_invalidator,
            });
        }
    }

    auto notify() -> void {
        // 拷贝一份，防止通知过程中 observers_ 被修改（重入）
        auto snapshot = observers_;
        // 清理不活跃条目
        observers_.erase(
            std::remove_if(observers_.begin(), observers_.end(),
                [](const detail::ObserverEntry& e){ return !e.active; }),
            observers_.end());
        for (auto& entry : snapshot) {
            if (entry.active) entry.invalidate();
        }
    }

    T                                        value_;
    mutable std::vector<detail::ObserverEntry> observers_;
    mutable std::size_t                      next_id_ = 1;
};

// ─── ReadSignal<T> ───────────────────────────────────────────────────────────
// Signal 的只读视图。持有指向原始 Signal 的非拥有指针。
// 只能读取，不能 set()。用于 Props 向子组件传递父状态。

template<typename T>
class ReadSignal {
public:
    explicit ReadSignal(const Signal<T>* source) : source_(source) {
        assert(source_ != nullptr);
    }

    [[nodiscard]] auto operator()() const -> const T& {
        return (*source_)();
    }

    [[nodiscard]] auto get() const -> const T& {
        return (*this)();
    }

private:
    const Signal<T>* source_ = nullptr;
};

// Signal<T>::as_read_only() 实现（需要 ReadSignal 完整定义后才能写）
template<typename T>
auto Signal<T>::as_read_only() const -> ReadSignal<T> {
    return ReadSignal<T>{ this };
}

// ─── Computed<T> ─────────────────────────────────────────────────────────────
// 派生状态。惰性求值：依赖 Signal 变化时标记 stale，
// 下次读取时重新计算。自动追踪内部所有 Signal 依赖。

template<typename F>
    requires std::invocable<F>
class Computed {
public:
    using ValueType = std::invoke_result_t<F>;

    explicit Computed(F compute_fn)
        : compute_fn_(std::move(compute_fn)), stale_(true) {}

    [[nodiscard]] auto operator()() const -> const ValueType& {
        if (stale_) recompute();
        // 若当前有 Effect 在追踪，也把自己的失效回调注册进去
        // （Computed 本身也是一种可观察的值）
        return cached_value_;
    }

private:
    auto recompute() const -> void {
        stale_ = false;
        // 设置 invalidator：当依赖 Signal 变化时，标记 stale 并重算
        std::function<void()> invalidator = [this]{ stale_ = true; };
        auto* prev = detail::current_invalidator;
        detail::current_invalidator = &invalidator;
        cached_value_ = compute_fn_();
        detail::current_invalidator = prev;
    }

    F                      compute_fn_;
    mutable ValueType      cached_value_{};
    mutable bool           stale_;
};

// 推导指引：Computed fn = Computed([&]{ return x() + y(); });
template<typename F>
Computed(F) -> Computed<F>;

// ─── Effect ──────────────────────────────────────────────────────────────────
// 副作用对象。构造时立即执行 fn 并自动注册对所有读取 Signal 的依赖。
// 依赖 Signal 变化时重新执行 fn。
// RAII：析构时自动从所有依赖 Signal 的观察者列表中移除（通过将 active 置 false）。

class Effect {
public:
    template<typename F>
        requires std::invocable<F>
    explicit Effect(F&& fn) : fn_(std::forward<F>(fn)) {
        run();
    }

    Effect(const Effect&) = delete;
    auto operator=(const Effect&) -> Effect& = delete;

    Effect(Effect&& other) noexcept
        : fn_(std::move(other.fn_))
        , active_(other.active_)
        , self_invalidator_(std::move(other.self_invalidator_)) {
        other.active_ = false;
    }

    ~Effect() {
        // 标记失活，Signal 的观察者列表会在下次 notify 时清理此条目
        active_ = false;
    }

private:
    auto run() -> void {
        if (!active_) return;
        // invalidator：被依赖 Signal 变化时，重新执行 fn
        self_invalidator_ = [this]{ run(); };
        auto* prev = detail::current_invalidator;
        detail::current_invalidator = &self_invalidator_;
        fn_();
        detail::current_invalidator = prev;
    }

    std::function<void()> fn_;
    bool                  active_ = true;
    std::function<void()> self_invalidator_;
};

// ─── EffectScope ─────────────────────────────────────────────────────────────
// 批量持有 Effect。随 scope 析构时，所有 Effect 的 RAII 析构自动清理依赖。
// Component 基类内置一个 EffectScope，开发者不需要手动管理 Effect 生命周期。

class EffectScope {
public:
    template<typename F>
        requires std::invocable<F>
    auto add(F&& fn) -> void {
        effects_.emplace_back(std::forward<F>(fn));
    }

    auto clear() -> void {
        effects_.clear();
    }

    [[nodiscard]] auto size() const noexcept -> std::size_t {
        return effects_.size();
    }

private:
    std::vector<Effect> effects_;
};

} // namespace Nandina
```

### 2.2 新建 `src/components/Label.ixx`

创建文件 `src/components/Label.ixx`，内容如下：

```cpp
module;

#include <cstdint>
#include <memory>
#include <string>
#include <utility>

export module Nandina.Components.Label;

import Nandina.Core;
import Nandina.Reactive;

export namespace Nandina {

// Label：文字显示组件（MVP 实现，文字渲染暂为占位，M4 接入 FreeType+HarfBuzz）
// 支持两种使用方式：
//   1. 链式配置：Label::Create().text("Hello").font_size(16)
//   2. Signal 绑定：Label::Create({ .text = name.as_read_only() })

struct LabelProps {
    // 可选：来自父组件的只读 Signal 绑定
    // 若提供，Label 内部会自动追踪此 Signal 的变化
    const Signal<std::string>* text_signal = nullptr;
};

class Label final : public Component {
public:
    // ── 工厂函数 ─────────────────────────────────────────────────────────────

    [[nodiscard]] static auto Create() -> std::unique_ptr<Label> {
        return std::unique_ptr<Label>(new Label{});
    }

    [[nodiscard]] static auto Create(LabelProps props) -> std::unique_ptr<Label> {
        auto label = std::unique_ptr<Label>(new Label{});
        if (props.text_signal) {
            // 绑定父组件 Signal：父 Signal 变化时自动更新 label 内部文字
            label->scope_.add([l = label.get(), sig = props.text_signal]{
                l->text_.set((*sig)());
            });
        }
        return label;
    }

    // ── 链式配置 API ─────────────────────────────────────────────────────────

    auto text(std::string t) -> Label& {
        text_.set(std::move(t));
        return *this;
    }

    auto font_size(float size) -> Label& {
        font_size_ = size;
        mark_dirty();
        return *this;
    }

    auto text_color(std::uint8_t r, std::uint8_t g, std::uint8_t b,
                    std::uint8_t a = 255) -> Label& {
        text_r_ = r; text_g_ = g; text_b_ = b; text_a_ = a;
        mark_dirty();
        return *this;
    }

    // ── 读取器 ───────────────────────────────────────────────────────────────

    [[nodiscard]] auto get_text()      const noexcept -> const std::string& { return text_(); }
    [[nodiscard]] auto get_font_size() const noexcept -> float              { return font_size_; }
    [[nodiscard]] auto text_r()        const noexcept -> std::uint8_t       { return text_r_; }
    [[nodiscard]] auto text_g()        const noexcept -> std::uint8_t       { return text_g_; }
    [[nodiscard]] auto text_b()        const noexcept -> std::uint8_t       { return text_b_; }
    [[nodiscard]] auto text_a()        const noexcept -> std::uint8_t       { return text_a_; }

private:
    Label() {
        set_background(0, 0, 0, 0);  // Label 背景透明
        // 当 text_ 变化时，标记自身需要重绘
        scope_.add([this]{ 
            (void)text_();  // 读取以注册依赖
            mark_dirty(); 
        });
    }

    Signal<std::string> text_{ "" };
    float               font_size_ = 14.0f;
    std::uint8_t        text_r_ = 255, text_g_ = 255, text_b_ = 255, text_a_ = 255;
};

} // namespace Nandina
```

### 2.3 新建 `src/layout/Layout.ixx`

创建文件 `src/layout/Layout.ixx`，内容如下：

```cpp
module;

#include <algorithm>
#include <cstdint>
#include <memory>
#include <utility>
#include <vector>

export module Nandina.Layout;

import Nandina.Core;

export namespace Nandina {

// ─── 布局对齐枚举 ─────────────────────────────────────────────────────────────

enum class Align : std::uint8_t {
    start,
    center,
    end,
    stretch,
    space_between,
    space_around,
};

// ─── LayoutContainer 基类 ─────────────────────────────────────────────────────
// 负责在 present_frame 前调用 layout() 重新排列子项几何位置

class LayoutContainer : public Component {
public:
    // ── 链式配置 API ─────────────────────────────────────────────────────────

    auto gap(float g) -> LayoutContainer& {
        gap_ = g;
        mark_dirty();
        return *this;
    }

    auto padding(float p) -> LayoutContainer& {
        padding_top_ = padding_right_ = padding_bottom_ = padding_left_ = p;
        mark_dirty();
        return *this;
    }

    auto padding(float horizontal, float vertical) -> LayoutContainer& {
        padding_left_ = padding_right_ = horizontal;
        padding_top_ = padding_bottom_ = vertical;
        mark_dirty();
        return *this;
    }

    auto align_items(Align a) -> LayoutContainer& {
        align_items_ = a;
        mark_dirty();
        return *this;
    }

    auto justify_content(Align a) -> LayoutContainer& {
        justify_content_ = a;
        mark_dirty();
        return *this;
    }

    // add() 返回 LayoutContainer& 支持链式调用
    auto add(std::unique_ptr<Widget> child) -> LayoutContainer& {
        add_child(std::move(child));
        return *this;
    }

    // 触发布局计算（由 WindowController::present_frame 前调用）
    virtual auto layout() -> void = 0;

protected:
    float gap_             = 0.0f;
    float padding_top_     = 0.0f;
    float padding_right_   = 0.0f;
    float padding_bottom_  = 0.0f;
    float padding_left_    = 0.0f;
    Align align_items_     = Align::start;
    Align justify_content_ = Align::start;
};

// ─── Column：垂直布局容器 ──────────────────────────────────────────────────────

class Column final : public LayoutContainer {
public:
    [[nodiscard]] static auto Create() -> std::unique_ptr<Column> {
        return std::make_unique<Column>();
    }

    // 链式 API 返回 Column& 以保留具体类型
    auto gap(float g) -> Column& {
        LayoutContainer::gap(g);
        return *this;
    }

    auto padding(float p) -> Column& {
        LayoutContainer::padding(p);
        return *this;
    }

    auto padding(float h, float v) -> Column& {
        LayoutContainer::padding(h, v);
        return *this;
    }

    auto add(std::unique_ptr<Widget> child) -> Column& {
        LayoutContainer::add(std::move(child));
        return *this;
    }

    auto layout() -> void override {
        float cursor_y = y() + padding_top_;
        const float content_x = x() + padding_left_;
        const float content_w = width() - padding_left_ - padding_right_;

        for_each_child([&](Widget& child){
            child.set_bounds(content_x, cursor_y, content_w, child.height());
            cursor_y += child.height() + gap_;
        });
    }
};

// ─── Row：水平布局容器 ────────────────────────────────────────────────────────

class Row final : public LayoutContainer {
public:
    [[nodiscard]] static auto Create() -> std::unique_ptr<Row> {
        return std::make_unique<Row>();
    }

    auto gap(float g) -> Row& {
        LayoutContainer::gap(g);
        return *this;
    }

    auto padding(float p) -> Row& {
        LayoutContainer::padding(p);
        return *this;
    }

    auto padding(float h, float v) -> Row& {
        LayoutContainer::padding(h, v);
        return *this;
    }

    auto add(std::unique_ptr<Widget> child) -> Row& {
        LayoutContainer::add(std::move(child));
        return *this;
    }

    auto layout() -> void override {
        float cursor_x = x() + padding_left_;
        const float content_y = y() + padding_top_;
        const float content_h = height() - padding_top_ - padding_bottom_;

        for_each_child([&](Widget& child){
            child.set_bounds(cursor_x, content_y, child.width(), content_h);
            cursor_x += child.width() + gap_;
        });
    }
};

// ─── Stack：层叠布局容器 ───────────────────────────────────────────────────────

class Stack final : public LayoutContainer {
public:
    [[nodiscard]] static auto Create() -> std::unique_ptr<Stack> {
        return std::make_unique<Stack>();
    }

    auto add(std::unique_ptr<Widget> child) -> Stack& {
        LayoutContainer::add(std::move(child));
        return *this;
    }

    // Stack：所有子项覆盖在同一区域（父容器的内容区域）
    auto layout() -> void override {
        const float cx = x() + padding_left_;
        const float cy = y() + padding_top_;
        const float cw = width()  - padding_left_ - padding_right_;
        const float ch = height() - padding_top_  - padding_bottom_;

        for_each_child([&](Widget& child){
            child.set_bounds(cx, cy, cw, ch);
        });
    }
};

} // namespace Nandina
```

### 2.4 更新 `src/core/Widget.ixx`

在现有 `Widget` 类中增加 `parent_` 弱指针和 `has_dirty_child_` 标志，以及 `for_each_child` 公开方法。将文件完整替换为：

```cpp
module;

#include <functional>
#include <memory>
#include <utility>
#include <vector>

export module Nandina.Core.Widget;

import Nandina.Core.Event;
import Nandina.Core.Signal;

export namespace Nandina {

class Widget {
public:
    using Child    = std::unique_ptr<Widget>;
    using WidgetPtr = std::unique_ptr<Widget>;

    virtual ~Widget() = default;

    // ── 子树管理 ─────────────────────────────────────────────────────────────

    auto add_child(Child child) -> Widget& {
        child->parent_ = this;
        children_.push_back(std::move(child));
        mark_dirty();
        return *this;
    }

    auto for_each_child(std::function<void(Widget&)> fn) const -> void {
        for (const auto& child : children_) fn(*child);
    }

    // ── 几何 ─────────────────────────────────────────────────────────────────

    virtual auto set_bounds(float x, float y, float w, float h) noexcept -> Widget& {
        x_ = x; y_ = y; width_ = w; height_ = h;
        mark_dirty();
        return *this;
    }

    [[nodiscard]] auto x()      const noexcept -> float { return x_; }
    [[nodiscard]] auto y()      const noexcept -> float { return y_; }
    [[nodiscard]] auto width()  const noexcept -> float { return width_; }
    [[nodiscard]] auto height() const noexcept -> float { return height_; }

    [[nodiscard]] auto contains(float px, float py) const noexcept -> bool {
        return px >= x_ && px < x_ + width_ && py >= y_ && py < y_ + height_;
    }

    // ── 样式 ─────────────────────────────────────────────────────────────────

    [[nodiscard]] auto background()    const noexcept -> Color { return bg_color_; }
    [[nodiscard]] auto border_radius() const noexcept -> float { return border_radius_; }

    auto set_background(std::uint8_t r, std::uint8_t g, std::uint8_t b,
                        std::uint8_t a = 255) noexcept -> Widget& {
        bg_color_ = {r, g, b, a};
        mark_dirty();
        return *this;
    }

    auto set_border_radius(float r) noexcept -> Widget& {
        border_radius_ = r;
        mark_dirty();
        return *this;
    }

    // ── Dirty 标记 ───────────────────────────────────────────────────────────

    [[nodiscard]] auto is_dirty()           const noexcept -> bool { return dirty_; }
    [[nodiscard]] auto has_dirty_child()    const noexcept -> bool { return has_dirty_child_; }

    auto mark_dirty() noexcept -> void {
        dirty_ = true;
        // 向上冒泡：通知祖先节点子树中有 dirty 节点
        if (parent_ && !parent_->has_dirty_child_) {
            parent_->bubble_dirty_child();
        }
    }

    auto clear_dirty() noexcept -> void {
        dirty_           = false;
        has_dirty_child_ = false;
    }

    // ── 事件 ─────────────────────────────────────────────────────────────────

    auto dispatch_event(Event& event) -> bool {
        // 子节点优先（逆序，后加入的子节点在最上层）
        for (auto it = children_.rbegin(); it != children_.rend(); ++it) {
            if ((*it)->dispatch_event(event)) return true;
        }
        if (event.handled || !contains(event.x, event.y)) return false;
        return handle_event(event);
    }

    auto on_click(std::function<void()> handler) -> Connection {
        return clicked_.connect(std::move(handler));
    }

protected:
    virtual auto handle_event(Event& event) -> bool {
        if (event.type == EventType::click) {
            clicked_.emit();
            event.mark_handled();
            return true;
        }
        return false;
    }

    [[nodiscard]] auto children() const noexcept -> const std::vector<Child>& {
        return children_;
    }

private:
    auto bubble_dirty_child() noexcept -> void {
        has_dirty_child_ = true;
        if (parent_ && !parent_->has_dirty_child_) {
            parent_->bubble_dirty_child();
        }
    }

    // 几何
    float x_ = 0.0f, y_ = 0.0f, width_ = 0.0f, height_ = 0.0f;
    // 样式
    Color bg_color_{ 255, 255, 255, 255 };
    float border_radius_ = 0.0f;
    // 树结构
    Widget*             parent_          = nullptr;  // 非拥有，弱引用
    std::vector<Child>  children_;
    // Dirty 标记
    bool dirty_           = true;
    bool has_dirty_child_ = false;
    // 事件
    Signal<> clicked_;
};

// Component：业务组件基类，内置 EffectScope
// （EffectScope 在 Nandina.Reactive 中定义，Widget 不直接依赖）
class Component : public Widget {
public:
    using Ptr = std::unique_ptr<Component>;
    virtual ~Component() = default;
};

} // namespace Nandina
```

**注意**：`Component` 的 `EffectScope` 集成需要等 `Nandina.Reactive` 模块建立后，在后续的 `Core.ixx` 中更新 `Component` 的定义，此处先保留接口骨架。

