### 2.1 新建 `src/reactive/Reactive.ixx`

创建文件 `src/reactive/Reactive.ixx`，内容如下：

```cpp
module;

#include <cassert>
#include <cstddef>
#include <functional>
#include <memory>
#include <type_traits>
#include <utility>
#include <vector>

export module Nandina.Reactive;

export namespace Nandina {

// ─── 前向声明 ────────────────────────────────────────────────────────────────

class EffectScope;

namespace detail {
    // 当前正在执行的 Effect 的通知回调（线程局部，用于自动依赖追踪）
    // 当 Effect 执行时，其读取的每个 Signal 都将此回调注册为观察者
    inline thread_local std::function<void()>* current_invalidator = nullptr;

    struct ObserverEntry {
        std::size_t           id     = 0;
        bool                  active = true;
        std::function<void()> invalidate;  // 被依赖的 Signal 变化时调用
    };
}

// ─── Signal<T> ───────────────────────────────────────────────────────────────
// 响应式可读写状态容器。
// 读取时（operator()）自动将当前 Effect 注册为观察者。
// 写入时（set）通知所有活跃观察者。

template<typename T>
class ReadSignal;  // 前向声明

template<typename T>
class Signal {
public:
    explicit Signal(T initial_value) : value_(std::move(initial_value)) {}

    // 禁止拷贝，允许移动
    Signal(const Signal&) = delete;
    auto operator=(const Signal&) -> Signal& = delete;
    Signal(Signal&&) noexcept = default;
    auto operator=(Signal&&) noexcept -> Signal& = default;

    // 读取当前值，同时注册依赖
    [[nodiscard]] auto operator()() const -> const T& {
        track_access();
        return value_;
    }

    [[nodiscard]] auto get() const -> const T& {
        return (*this)();
    }

    // 写入新值，值变化时通知所有观察者
    auto set(T new_value) -> void {
        if (value_ == new_value) return;
        value_ = std::move(new_value);
        notify();
    }

    // 返回只读视图（传给子组件的 Props，防止子组件反向写入）
    [[nodiscard]] auto as_read_only() const -> ReadSignal<T>;

private:
    friend class ReadSignal<T>;

    auto track_access() const -> void {
        if (detail::current_invalidator) {
            // 为当前 Effect 注册一个观察者条目
            const std::size_t id = next_id_++;
            observers_.push_back(detail::ObserverEntry{
                .id         = id,
                .active     = true,
                .invalidate = *detail::current_invalidator,
            });
        }
    }

    auto notify() -> void {
        // 拷贝一份，防止通知过程中 observers_ 被修改（重入）
        auto snapshot = observers_;
        // 清理不活跃条目
        observers_.erase(
            std::remove_if(observers_.begin(), observers_.end(),
                [](const detail::ObserverEntry& e){ return !e.active; }),
            observers_.end());
        for (auto& entry : snapshot) {
            if (entry.active) entry.invalidate();
        }
    }

    T                                        value_;
    mutable std::vector<detail::ObserverEntry> observers_;
    mutable std::size_t                      next_id_ = 1;
};

// ─── ReadSignal<T> ───────────────────────────────────────────────────────────
// Signal 的只读视图。持有指向原始 Signal 的非拥有指针。
// 只能读取，不能 set()。用于 Props 向子组件传递父状态。

template<typename T>
class ReadSignal {
public:
    explicit ReadSignal(const Signal<T>* source) : source_(source) {
        assert(source_ != nullptr);
    }

    [[nodiscard]] auto operator()() const -> const T& {
        return (*source_)();
    }

    [[nodiscard]] auto get() const -> const T& {
        return (*this)();
    }

private:
    const Signal<T>* source_ = nullptr;
};

// Signal<T>::as_read_only() 实现（需要 ReadSignal 完整定义后才能写）
template<typename T>
auto Signal<T>::as_read_only() const -> ReadSignal<T> {
    return ReadSignal<T>{ this };
}

// ─── Computed<T> ─────────────────────────────────────────────────────────────
// 派生状态。惰性求值：依赖 Signal 变化时标记 stale，
// 下次读取时重新计算。自动追踪内部所有 Signal 依赖。

template<typename F>
    requires std::invocable<F>
class Computed {
public:
    using ValueType = std::invoke_result_t<F>;

    explicit Computed(F compute_fn)
        : compute_fn_(std::move(compute_fn)), stale_(true) {}

    [[nodiscard]] auto operator()() const -> const ValueType& {
        if (stale_) recompute();
        // 若当前有 Effect 在追踪，也把自己的失效回调注册进去
        // （Computed 本身也是一种可观察的值）
        return cached_value_;
    }

private:
    auto recompute() const -> void {
        stale_ = false;
        // 设置 invalidator：当依赖 Signal 变化时，标记 stale 并重算
        std::function<void()> invalidator = [this]{ stale_ = true; };
        auto* prev = detail::current_invalidator;
        detail::current_invalidator = &invalidator;
        cached_value_ = compute_fn_();
        detail::current_invalidator = prev;
    }

    F                      compute_fn_;
    mutable ValueType      cached_value_{};
    mutable bool           stale_;
};

// 推导指引：Computed fn = Computed([&]{ return x() + y(); });
template<typename F>
Computed(F) -> Computed<F>;

// ─── Effect ──────────────────────────────────────────────────────────────────
// 副作用对象。构造时立即执行 fn 并自动注册对所有读取 Signal 的依赖。
// 依赖 Signal 变化时重新执行 fn。
// RAII：析构时自动从所有依赖 Signal 的观察者列表中移除（通过将 active 置 false）。

class Effect {
public:
    template<typename F>
        requires std::invocable<F>
    explicit Effect(F&& fn) : fn_(std::forward<F>(fn)) {
        run();
    }

    Effect(const Effect&) = delete;
    auto operator=(const Effect&) -> Effect& = delete;

    Effect(Effect&& other) noexcept
        : fn_(std::move(other.fn_))
        , active_(other.active_)
        , self_invalidator_(std::move(other.self_invalidator_)) {
        other.active_ = false;
    }

    ~Effect() {
        // 标记失活，Signal 的观察者列表会在下次 notify 时清理此条目
        active_ = false;
    }

private:
    auto run() -> void {
        if (!active_) return;
        // invalidator：被依赖 Signal 变化时，重新执行 fn
        self_invalidator_ = [this]{ run(); };
        auto* prev = detail::current_invalidator;
        detail::current_invalidator = &self_invalidator_;
        fn_();
        detail::current_invalidator = prev;
    }

    std::function<void()> fn_;
    bool                  active_ = true;
    std::function<void()> self_invalidator_;
};

// ─── EffectScope ─────────────────────────────────────────────────────────────
// 批量持有 Effect。随 scope 析构时，所有 Effect 的 RAII 析构自动清理依赖。
// Component 基类内置一个 EffectScope，开发者不需要手动管理 Effect 生命周期。

class EffectScope {
public:
    template<typename F>
        requires std::invocable<F>
    auto add(F&& fn) -> void {
        effects_.emplace_back(std::forward<F>(fn));
    }

    auto clear() -> void {
        effects_.clear();
    }

    [[nodiscard]] auto size() const noexcept -> std::size_t {
        return effects_.size();
    }

private:
    std::vector<Effect> effects_;
};

} // namespace Nandina
```

