        col->add(Label::Create().text("豆子：" + props.bean));

        auto btn = Button::Create().text("水洗 → 下一步");
        btn->on_click([this]{
            router()->push<BrewPage>(BrewProps{
                .bean    = props.bean,
                .process = "水洗"
            });
