// WindowController 只需要初始化 Router
class CoffeeApp : public WindowController {
    auto build_root() -> WidgetPtr override {
        router_.push<BeanSelectPage>();  // 初始页
        return RouterView::Create(router_);
    }
    Router router_;
};
```

