## 三、`Page<Props>` —— 新建

### 路径：`src/core/Page.ixx`

`Page` 是 `CompositeComponent` 的全屏特化，增加：
- `on_enter()` / `on_leave()` 生命周期钩子
- `router()` 访问当前 Router 的方法
- Router 注入（由 RouterView 在挂载时注入）

```cpp
module;
#include <memory>

export module Nandina.Core.Page;

import Nandina.Core.CompositeComponent;
import Nandina.Core.Widget;

export namespace Nandina {

// 前向声明
class Router;

// ── Page<Props> ─────────────────────────────────────────────────────────────
template<typename Props = void>
class Page : public CompositeComponent<Props> {
public:
    // 生命周期钩子，Router 在 push/pop 时调用
    virtual auto on_enter() -> void {}
    virtual auto on_leave() -> void {}

    // 访问持有此 Page 的 Router
    // 在 Page 被 Router push 之后才有效
    [[nodiscard]] auto router() noexcept -> Router* { return router_; }
    [[nodiscard]] auto router() const noexcept -> const Router* { return router_; }

    // 由 Router 内部调用，注入 router 指针
    auto set_router(Router* r) noexcept -> void { router_ = r; }

protected:
    Router* router_ = nullptr;
};

} // namespace Nandina
```

注意：`Page` 依赖 `Router` 的前向声明就够了（只用指针），`Router` 定义在独立模块中。

