## 四、`Router` + `RouterView` —— 新建

### 路径：`src/core/Router.ixx`

**Router 核心设计：**
- 持有 `std::vector<std::unique_ptr<PageBase>>` 作为页面栈
- `push<PageType>()` / `push<PageType>(Props)` 创建页面并推栈
- `pop()` 弹栈，调用生命周期
- `replace<PageType>()` 替换当前页（不保留历史）
- `current()` 返回当前 Page 指针（类型擦除的基类指针）
- 内部有一个 `State<int> version_` 用于通知 RouterView 当前页变化了

```cpp
module;
#include <cassert>
#include <memory>
#include <utility>
#include <vector>

export module Nandina.Core.Router;

import Nandina.Core.Page;
import Nandina.Reactive;
import Nandina.Core.Widget;

export namespace Nandina {

// 类型擦除的 Page 基类（无 Props 版本作为公共接口）
// Router 用 PageBase* 持有所有页面，不关心具体 Props 类型
using PageBase = Page<void>;

class Router {
public:
    Router() = default;

    // ── push：压栈（无 Props 页面）─────────────────────────────────────────
    template<typename PageType>
        requires std::is_base_of_v<PageBase, PageType>
    auto push() -> void {
        auto page = std::unique_ptr<PageType>(new PageType());
        page->set_router(this);
        page->initialize();
        if (!stack_.empty()) {
            stack_.back()->on_leave();
        }
        page->on_enter();
        stack_.push_back(std::move(page));
        version_.set(version_.get() + 1);  // 通知 RouterView
    }

    // ── push：压栈（有 Props 页面）─────────────────────────────────────────
    // 因为 Page<Props> 和 Page<void> 不是同一基类，需要特殊处理。
    // 推荐方案：有 Props 的 Page 继承 Page<void> 并在构造时接受 Props。
    // 见下方"有 Props 的 Page 写法"说明。
    template<typename PageType, typename Props>
        requires std::is_base_of_v<PageBase, PageType>
    auto push(Props props) -> void {
        auto page = std::unique_ptr<PageType>(new PageType(std::move(props)));
        page->set_router(this);
        page->initialize();
        if (!stack_.empty()) {
            stack_.back()->on_leave();
        }
        page->on_enter();
        stack_.push_back(std::move(page));
        version_.set(version_.get() + 1);
    }

    // ── pop ────────────────────────────────────────────────────────────────
    auto pop() -> void {
        if (stack_.empty()) return;
        stack_.back()->on_leave();
        stack_.pop_back();
        if (!stack_.empty()) {
            stack_.back()->on_enter();
        }
        version_.set(version_.get() + 1);
    }

    // ── replace ────────────────────────────────────────────────────────────
    template<typename PageType>
        requires std::is_base_of_v<PageBase, PageType>
    auto replace() -> void {
        if (!stack_.empty()) {
            stack_.back()->on_leave();
            stack_.pop_back();
        }
        push<PageType>();
    }

    template<typename PageType, typename Props>
        requires std::is_base_of_v<PageBase, PageType>
    auto replace(Props props) -> void {
        if (!stack_.empty()) {
            stack_.back()->on_leave();
            stack_.pop_back();
        }
        push<PageType>(std::move(props));
    }

    // ── current ────────────────────────────────────────────────────────────
    [[nodiscard]] auto current() noexcept -> PageBase* {
        if (stack_.empty()) return nullptr;
        return stack_.back().get();
    }

    [[nodiscard]] auto depth() const noexcept -> std::size_t {
        return stack_.size();
    }

    // RouterView 订阅此 State 来感知页面变化
    [[nodiscard]] auto version() const noexcept -> ReadState<int> {
        return version_.as_read_only();
    }

private:
    std::vector<std::unique_ptr<PageBase>> stack_;
    State<int> version_{ 0 };
};


// ── RouterView ──────────────────────────────────────────────────────────────
// 展示 Router 当前 Page 的容器 Widget。
// 当 Router 的 version State 变化时，自动切换显示的子节点。
class RouterView : public Component {
public:
    static auto Create(Router& router) -> std::unique_ptr<RouterView> {
        return std::unique_ptr<RouterView>(new RouterView(router));
    }

    // RouterView 自身占满父容器，set_bounds 时同步给当前 Page
    auto set_bounds(float x, float y, float w, float h) noexcept -> Widget& override {
        Component::set_bounds(x, y, w, h);
        sync_page_bounds();
        return *this;
    }

private:
    explicit RouterView(Router& router) : router_(router) {
        set_background(0, 0, 0, 0);  // 透明背景，让 Page 自己画

        // 当 Router 的 version 变化时，重新挂载当前 Page
        scope_.add([this]{
            (void)router_.version()();  // 读取以注册依赖
            mount_current_page();
        });
    }

    auto mount_current_page() -> void {
        // 清空现有子节点（释放前一个 Page 的 Widget 引用）
        // 注意：Router 拥有 Page 的生命周期，RouterView 只是"视图"引用
        // 用 clear_children() 清除子节点列表但不 delete（Page 由 Router 持有）
        clear_children_non_owning();

        if (auto* page = router_.current()) {
            // 将当前 Page 作为非拥有子节点添加
            add_child_non_owning(page);
            sync_page_bounds();
        }
        mark_dirty();
    }

    auto sync_page_bounds() -> void {
        if (auto* page = router_.current()) {
            page->set_bounds(x(), y(), width(), height());
        }
    }

    Router& router_;
};

} // namespace Nandina
```

**关于 `add_child_non_owning` 的问题：**

当前 `Widget::add_child` 接受 `std::unique_ptr<Widget>`，会获取所有权。但 RouterView 不拥有 Page（Router 拥有），所以需要在 `Widget` 中增加**非拥有引用**的挂载方式。

推荐方案：在 `Widget` 中增加：
```cpp
// 非拥有子节点引用（用于 RouterView 等特殊场景）
auto add_child_ref(Widget* child) -> Widget& {
    // 用一个不做 delete 的自定义 deleter 包装原始指针
    child->parent_ = this;
    children_ref_.push_back(child);  // 单独存放，不参与 unique_ptr 所有权
    mark_dirty();
    return *this;
}

auto clear_children_ref() -> void {
    for (auto* c : children_ref_) {
        if (c) c->parent_ = nullptr;
    }
    children_ref_.clear();
    mark_dirty();
}

// for_each_child 也要遍历 children_ref_
```

同时更新 `dispatch_event`、`for_each_child`、`render_widget` 逻辑，让它们同时遍历 `children_`（拥有的）和 `children_ref_`（非拥有的引用）。

在 Widget 中增加：
```cpp
private:
    std::vector<Widget*> children_ref_;  // 非拥有引用，由外部（如 Router）管理生命周期
```

**更新 `Core.ixx`：**
```cpp
export import Nandina.Core.Router;
```

