## 三、`RenderLayer` 系统

### 3.1 新建 `src/core/RenderLayer.ixx`

```cpp
module;
#include <algorithm>
#include <array>
#include <cstddef>
#include <memory>
#include <utility>
#include <vector>

export module Nandina.Core.RenderLayer;

import Nandina.Core.Widget;
import Nandina.Core.Event;

export namespace Nandina {

// 单个渲染层：独立的 Widget 树根 + 渲染/事件上下文
struct RenderLayer {
    int  index  = 0;
    bool modal  = false;   // true 时：该层及以上正常，该层以下事件被屏蔽
    bool visible = true;

    // 该层的根节点（占满窗口，通常是 Stack 或 FreeWidget 容器）
    std::unique_ptr<Widget> root;

    [[nodiscard]] auto has_content() const noexcept -> bool {
        return root != nullptr;
    }

    // 向该层添加一个 FreeWidget（层持有所有权）
    // 返回裸指针供后续操作
    template<typename T>
    auto add(std::unique_ptr<T> widget) -> T* {
        auto* ptr = widget.get();
        if (!root) {
            // 如果层没有根节点，第一个添加的就是根节点
            root = std::move(widget);
        } else {
            root->add_child(std::move(widget));
        }
        return ptr;
    }
};

} // namespace Nandina
```

### 3.2 修改 `src/core/Window.ixx` — `WindowController`

将 `WindowController` 从"单 root Widget"升级为"16 层 RenderLayer 管理器"。

**主要修改点：**

#### `NanWindow` 类修改

`NanWindow::set_root()` 改为 `NanWindow::set_layers()`，接受指向 `std::array<RenderLayer, 16>` 的引用（或拷贝）。

渲染逻辑从"渲染单个 root" 改为：
```cpp
// 按层顺序渲染（0 → 15），跳过没有内容的层
auto present_frame() -> void {
    canvas_->remove(nullptr); // 清空上一帧

    for (auto& layer : layers_) {
        if (layer.visible && layer.has_content()) {
            render_widget(*layer.root);
        }
    }
    // ... 后续 SDL 呈现逻辑不变
}
```

事件分发改为从高层到低层，遇到 modal 层就停止向下：
```cpp
auto translate_and_dispatch(const SDL_Event& sdl_event) -> void {
    // 构造 Nandina Event
    Event ev = translate_event(sdl_event);

    // 从最高有内容的层开始向下分发
    for (int i = 15; i >= 0; --i) {
        auto& layer = layers_[i];
        if (!layer.visible || !layer.has_content()) continue;

        layer.root->dispatch_event(ev);

        if (ev.handled) break;          // 已被处理，停止向下
        if (layer.modal) break;         // 模态层：即使未处理也阻止向下传递
    }
}
```

#### `WindowController` 修改

```cpp
class WindowController {
public:
    virtual ~WindowController() = default;

    auto exec() -> int {
        auto window = NanWindow::Builder{}
            .set_title(title())
            .set_width(initial_size().first)
            .set_height(initial_size().second)
            .build();

        // 调用派生类的 setup_layers()，由用户填充各层内容
        setup_layers(layers_);
        window.set_layers(layers_);

        on_start();
        while (!window.process_events()) {
            on_frame();
            window.present_frame();
        }
        on_shutdown();
        return 0;
    }

protected:
    // ── 语义化层访问器（对应 Godot 的惯用层号）──────────────────────────
    auto world_layer()   -> RenderLayer& { return layers_[0]; }  // Node2D / FreeCanvas
    auto ui_layer()      -> RenderLayer& { return layers_[1]; }  // 主 UI，RouterView
    auto overlay_layer() -> RenderLayer& { return layers_[2]; }  // Popover/Toast/Dock
    auto modal_layer()   -> RenderLayer& { return layers_[3]; }  // Dialog（模态）
    auto layer(int i)    -> RenderLayer& { return layers_[i]; }  // 任意层

    // ── 派生类实现这个来配置各层 ──────────────────────────────────────────
    // 取代原来的 build_root()
    // 默认实现：调用旧的 build_root() 并放到 ui_layer()（向后兼容）
    virtual auto setup_layers(std::array<RenderLayer, 16>& layers) -> void {
        // 向后兼容：如果派生类只重写了 build_root()，自动放到 Layer 1
        auto root = build_root();
        if (root) {
            layers[1].root = std::move(root);
        }
    }

    // 向后兼容：保留 build_root() 接口，默认返回 nullptr
    virtual auto build_root() -> std::unique_ptr<Widget> { return nullptr; }

    [[nodiscard]] virtual auto title() const -> std::string_view { return "Nandina Window"; }
    [[nodiscard]] virtual auto initial_size() const -> std::pair<int, int> { return {800, 600}; }
    virtual auto on_start()    -> void {}
    virtual auto on_frame()    -> void {}
    virtual auto on_shutdown() -> void {}

    std::array<RenderLayer, 16> layers_;
};
```

**兼容性**：现有的 `ApplicationWindow` 只重写了 `build_root()`，`setup_layers()` 的默认实现自动把它放到 `ui_layer()`，不需要修改现有代码。

