```cpp
module;
#include <functional>
#include <variant>

export module Nandina.Reactive.Prop;

import Nandina.Core.Signal;
import Nandina.Reactive;

export namespace Nandina {

// Prop<T> unifies a static value and a reactive State<T> reference.
// Components declare their inputs as Prop<T>, so callers can pass
// either a plain value or a live State<T> without changing the API.
template<typename T>
class Prop {
public:
    // Implicit construction from a static value
    Prop(T value) : value_(std::move(value)) {}

    // Implicit construction from a State<T> reference (reactive binding)
    Prop(State<T>& state) : value_(std::ref(state)) {}

    Prop(const Prop&) = delete;
    auto operator=(const Prop&) = delete;
    Prop(Prop&&) noexcept = default;
    auto operator=(Prop&&) noexcept -> Prop& = default;

    // Read current value (tracks reactive access if inside an Effect)
    [[nodiscard]] auto get() const -> const T& {
        if (auto* s = std::get_if<std::reference_wrapper<State<T>>>(&value_)) {
            return s->get().get();
        }
        return std::get<T>(value_);
    }

    [[nodiscard]] auto operator()() const -> const T& { return get(); }

    [[nodiscard]] auto is_reactive() const -> bool {
        return std::holds_alternative<std::reference_wrapper<State<T>>>(value_);
    }

    // Register a callback invoked whenever the value changes.
    // For a static Prop, the callback is never called (returns empty Connection).
    // For a reactive Prop, subscribes to State<T> changes via an Effect stored
    // in an EventSignal so the caller can disconnect via the returned Connection.
    auto on_change(std::function<void(const T&)> callback) -> Connection {
        if (!is_reactive()) { return Connection{}; }
        auto& state = std::get<std::reference_wrapper<State<T>>>(value_).get();
        return change_signal_.connect([&state, cb = std::move(callback)]() {
            cb(state.get());
        });
    }

private:
    std::variant<T, std::reference_wrapper<State<T>>> value_;
    EventSignal<> change_signal_;  // internal signal used to bridge State→callback
};

} // export namespace Nandina
```

**Important note about `Prop<T>::on_change`**: The approach above has a lifetime issue. A simpler and safer approach is to have the caller register Effects via the `EffectScope` of the owning Component. So implement `on_change` as follows — it returns a `Connection` that wraps a slot on an internal `EventSignal<>`, and whenever `State<T>` notifies, the Prop re-emits. Since we can't subscribe to State changes directly without an Effect, expose a helper:

```cpp
// Simpler and correct version:
// on_change returns a Connection for unsubscription.
// The Component should call this inside an effect() so the State tracking works naturally.
// For static Props, on_change callback is never invoked.
auto on_change(std::function<void(const T&)> callback) -> Connection {
    return change_signal_.connect([this, cb = std::move(callback)]() {
        cb(get());
    });
}

// Called by the framework when the underlying State changes.
// Components wire this up inside their EffectScope.
auto notify_change() -> void {
    change_signal_.emit();
}
```

And document that for reactive Props, the user should call `get()` inside an `effect()` — the reactive tracking through `State<T>::operator()()` will re-run the effect automatically. The `on_change` + `notify_change` mechanism is an alternative for imperative-style notification.

**Final simplified design** — keep Prop.ixx simple and correct:

```cpp
module;
#include <functional>
#include <variant>

export module Nandina.Reactive.Prop;

import Nandina.Core.Signal;
import Nandina.Reactive;

export namespace Nandina {

template<typename T>
class Prop {
public:
    Prop(T value) : value_(std::move(value)) {}
    Prop(State<T>& state) : value_(std::ref(state)) {}

    Prop(const Prop&) = delete;
    auto operator=(const Prop&) = delete;
    Prop(Prop&&) noexcept = default;
    auto operator=(Prop&&) noexcept -> Prop& = default;

    // Read current value. When called inside an Effect, reactive Props
    // auto-register as dependencies.
    [[nodiscard]] auto get() const -> const T& {
        if (auto* s = std::get_if<std::reference_wrapper<State<T>>>(&value_)) {
            return s->get()();  // operator() tracks access in the current Effect
        }
        return std::get<T>(value_);
    }

    [[nodiscard]] auto operator()() const -> const T& { return get(); }

    [[nodiscard]] auto is_reactive() const -> bool {
        return std::holds_alternative<std::reference_wrapper<State<T>>>(value_);
    }

private:
    std::variant<T, std::reference_wrapper<State<T>>> value_;
};

} // export namespace Nandina
```

