```cpp
module;
#include <cstddef>
#include <functional>
#include <optional>
#include <utility>
#include <vector>

export module Nandina.Reactive.StateList;

import Nandina.Core.Signal;

export namespace Nandina {

enum class ListChangeKind : unsigned char {
    Inserted,
    Removed,
    Updated,
    Reset,
};

template<typename T>
struct ListChange {
    ListChangeKind   kind;
    std::size_t      index    = 0;
    std::optional<T> old_value;  // valid for Removed / Updated
    std::optional<T> new_value;  // valid for Inserted / Updated
};

// StateList<T> — an observable vector.
// Fine-grained ListChange notifications allow consumers (e.g., a list widget)
// to perform incremental updates instead of full rebuilds.
template<typename T>
class StateList {
public:
    StateList() = default;

    // ── Read ──────────────────────────────────────────────────────────────────
    [[nodiscard]] auto size()  const noexcept -> std::size_t { return data_.size(); }
    [[nodiscard]] auto empty() const noexcept -> bool        { return data_.empty(); }

    [[nodiscard]] auto at(std::size_t i) const -> const T& { return data_.at(i); }
    [[nodiscard]] auto operator[](std::size_t i) const -> const T& { return data_[i]; }

    [[nodiscard]] auto begin() const { return data_.cbegin(); }
    [[nodiscard]] auto end()   const { return data_.cend(); }

    // ── Write ─────────────────────────────────────────────────────────────────
    auto push_back(T value) -> void {
        const std::size_t idx = data_.size();
        data_.push_back(value);
        on_change_.emit(ListChange<T>{ListChangeKind::Inserted, idx, std::nullopt, std::move(value)});
        on_any_.emit();
    }

    auto insert(std::size_t index, T value) -> void {
        data_.insert(data_.begin() + static_cast<std::ptrdiff_t>(index), value);
        on_change_.emit(ListChange<T>{ListChangeKind::Inserted, index, std::nullopt, std::move(value)});
        on_any_.emit();
    }

    auto remove_at(std::size_t index) -> void {
        if (index >= data_.size()) { return; }
        T old = data_[index];
        data_.erase(data_.begin() + static_cast<std::ptrdiff_t>(index));
        on_change_.emit(ListChange<T>{ListChangeKind::Removed, index, std::move(old), std::nullopt});
        on_any_.emit();
    }

    auto update_at(std::size_t index, T new_value) -> void {
        if (index >= data_.size()) { return; }
        T old = data_[index];
        data_[index] = new_value;
        on_change_.emit(ListChange<T>{ListChangeKind::Updated, index, std::move(old), std::move(new_value)});
        on_any_.emit();
    }

    auto assign_all(std::vector<T> new_data) -> void {
        data_ = std::move(new_data);
        on_change_.emit(ListChange<T>{ListChangeKind::Reset, 0, std::nullopt, std::nullopt});
        on_any_.emit();
    }

    auto clear() -> void {
        data_.clear();
        on_change_.emit(ListChange<T>{ListChangeKind::Reset, 0, std::nullopt, std::nullopt});
        on_any_.emit();
    }

    // ── Subscribe ─────────────────────────────────────────────────────────────
    // Fine-grained: receive a ListChange describing exactly what changed.
    auto on_change(std::function<void(const ListChange<T>&)> cb) -> Connection {
        return on_change_.connect(std::move(cb));
    }

    // Coarse-grained: called on any mutation (simpler for full-rebuild scenarios).
    auto watch(std::function<void()> cb) -> Connection {
        return on_any_.connect(std::move(cb));
    }

private:
    std::vector<T>                    data_;
    EventSignal<ListChange<T>>        on_change_;
    EventSignal<>                     on_any_;
};

} // export namespace Nandina
```

