## Three features to implement

### Feature 1: `src/reactive/Prop.ixx` (new file)

Create module `Nandina.Reactive.Prop`. Prop<T> unifies a static value and a reactive `State<T>` reference as a component input parameter. Callers can pass either a plain T or a `State<T>&` without changing the component API.

```cpp
module;
#include <functional>
#include <variant>

export module Nandina.Reactive.Prop;

import Nandina.Core.Signal;
import Nandina.Reactive;

export namespace Nandina {

// Prop<T> — component input that accepts either a static T value or a
// live State<T> reference. When used inside an effect(), reactive Props
// automatically register as reactive dependencies.
template<typename T>
class Prop {
public:
    Prop(T value) : value_(std::move(value)) {}                // static binding
    Prop(State<T>& state) : value_(std::ref(state)) {}         // reactive binding

    Prop(const Prop&) = delete;
    auto operator=(const Prop&) = delete;
    Prop(Prop&&) noexcept = default;
    auto operator=(Prop&&) noexcept -> Prop& = default;

    // get() inside an Effect: reactive Props auto-subscribe via State<T>::operator()
    [[nodiscard]] auto get() const -> const T& {
        if (auto* s = std::get_if<std::reference_wrapper<State<T>>>(&value_)) {
            return s->get()();   // calls State<T>::operator(), tracking access
        }
        return std::get<T>(value_);
    }

    [[nodiscard]] auto operator()() const -> const T& { return get(); }

    [[nodiscard]] auto is_reactive() const -> bool {
        return std::holds_alternative<std::reference_wrapper<State<T>>>(value_);
    }

private:
    std::variant<T, std::reference_wrapper<State<T>>> value_;
};

} // export namespace Nandina
```

### Feature 2: `src/reactive/StateList.ixx` (new file)

Create module `Nandina.Reactive.StateList`. StateList<T> is an observable vector with fine-grained change notifications.

```cpp
module;
#include <cstddef>
#include <functional>
#include <optional>
#include <utility>
#include <vector>

export module Nandina.Reactive.StateList;

import Nandina.Core.Signal;

export namespace Nandina {

enum class ListChangeKind : unsigned char {
    Inserted,
    Removed,
    Updated,
    Reset,
};

template<typename T>
struct ListChange {
    ListChangeKind   kind;
    std::size_t      index     = 0;
    std::optional<T> old_value;
    std::optional<T> new_value;
};

template<typename T>
class StateList {
public:
    StateList() = default;

    [[nodiscard]] auto size()  const noexcept -> std::size_t { return data_.size(); }
    [[nodiscard]] auto empty() const noexcept -> bool        { return data_.empty(); }
    [[nodiscard]] auto at(std::size_t i)        const -> const T& { return data_.at(i); }
    [[nodiscard]] auto operator[](std::size_t i) const -> const T& { return data_[i]; }
    [[nodiscard]] auto begin() const { return data_.cbegin(); }
    [[nodiscard]] auto end()   const { return data_.cend(); }

    auto push_back(T value) -> void {
        const std::size_t idx = data_.size();
        data_.push_back(value);
        on_change_.emit(ListChange<T>{ListChangeKind::Inserted, idx, std::nullopt, std::move(value)});
        on_any_.emit();
    }

    auto remove_at(std::size_t index) -> void {
        if (index >= data_.size()) { return; }
        T old = data_[index];
        data_.erase(data_.begin() + static_cast<std::ptrdiff_t>(index));
        on_change_.emit(ListChange<T>{ListChangeKind::Removed, index, std::move(old), std::nullopt});
        on_any_.emit();
    }

    auto clear() -> void {
        data_.clear();
        on_change_.emit(ListChange<T>{ListChangeKind::Reset, 0, std::nullopt, std::nullopt});
        on_any_.emit();
    }

    auto on_change(std::function<void(const ListChange<T>&)> cb) -> Connection {
        return on_change_.connect(std::move(cb));
    }

    auto watch(std::function<void()> cb) -> Connection {
        return on_any_.connect(std::move(cb));
    }

private:
    std::vector<T>             data_;
    EventSignal<ListChange<T>> on_change_;
    EventSignal<>              on_any_;
};

} // export namespace Nandina
```

